        {
          "type": "text",
          "text": "Du siehst einen österreichischen Zulassungsschein (Kraftfahrzeugbrief). Extrahiere die folgenden Felder und gib NUR ein JSON-Objekt zurück, ohne zusätzlichen Text:\n\n{\n  \"marke\": \"Hersteller/Marke (z.B. Volkswagen)\",\n  \"modell\": \"Modell/Typ (z.B. Golf 1.6 TDI)\",\n  \"kennzeichen\": \"amtliches Kennzeichen (z.B. W-12345A)\",\n  \"erstzulassung\": \"Datum TT.MM.JJJJ\",\n  \"fin\": \"Fahrgestellnummer/VIN (17 Zeichen)\",\n  \"kraftstoff\": \"Kraftstoffart (Diesel/Benzin/Elektro/Hybrid)\",\n  \"farbe\": \"Farbe des Fahrzeugs\",\n  \"leistungKw\": \"Motorleistung in kW als Zahl ohne Einheit\"\n}\n\nFalls ein Feld nicht lesbar ist, verwende einen leeren String."
        }
      ]
    }
  ]
}

parameters.jsCode:
const response = $input.first().json;

try {
  const text = response.content[0].text;
  // JSON aus der Antwort extrahieren
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('Kein JSON in Antwort');
  const parsed = JSON.parse(jsonMatch[0]);
  return [{ json: parsed }];
} catch (e) {
  return [{ json: { error: 'Zulassungsschein konnte nicht gelesen werden. Bitte manuell ausfüllen.' } }];
}
